RooDalitzTimeCPCBTAG::RooDalitzTimeCPCBTAG(const char *name, const char *title,
	RooRealVar& t,
	RooAbsReal& mhh,   //m(hh)
	RooAbsReal& coshh, //cos(hh)
	RooAbsReal& cosH,  //cos(jpsi)
	RooAbsReal& chi,   //chi angle
	TH2F & etapdf,
	RooAbsCategory& tag1, RooAbsReal& eta1,
	RooAbsCategory& tag2, RooAbsReal& eta2, 
	RooArgList efftag, RooAbsReal &defftag,
	RooArgList Calibtag, RooArgList dCalibtag, 
	RooAbsReal& tau, RooAbsReal& dgamma, 
	RooAbsReal& dm, 
	TList *cpList, TList *resList, 
	TList *effList,
	double ML, double MR,					      
	const RooResolutionModel &resModel,
	DecayType dtype,
	double FFR,
	double FFB):
   RooAbsAnaConvPdf(name,title, resModel, t), 
   RooDalitzAmplitude(resList, cpList, effList, ML, MR, FFR, FFB),
   _t("t","t",this,t),
   _mhh("mhh","invariant mass pipi",this,mhh),
   _coshh("coshh","cos(theta_hh)",this,coshh),
   _cosH("cosH","cos(Helicity of J/psi", this, cosH),
   _chi("chi","angle of two decay planes", this, chi),
   _etapdf(etapdf),
   _tag1("tag1","Tag state1",this,tag1),
   _eta1("eta1","mistag ratio1",this,eta1),
   _tag2("tag2","Tag state2",this,tag2),
   _eta2("eta2","mistag ratio2",this,eta2),
   _dCalibtag("dCalibtag", "list of #DeltaMistag", this),
   _Calibtag("Calibtag", "list of calib parameters", this),
   _efftag("efftag", "tag eff", this),
   _RP("defftag", "Produce Ratio BBar/B", this, defftag),  
   _tau("tau","tau",this,tau),
   _dgamma("dgamma","dgamma",this,dgamma),
   _dm("dm","dm",this,dm),
   _dtype(dtype),
   _resParams("resParams", "Parameters for resonaces", this),
   _cpParams("cpParams", "Parameters for CP violation", this),  
   _Rsum(0),  _Rdif(0),  _RInterf(0),
   _RsumInt(0),  _RdifInt(0),  _RInterfInt(0),
   _redoInt(1)
{ 
   _dCalibtag.add(dCalibtag);
   _Calibtag.add(Calibtag);
   _efftag.add(efftag);
   //Constructor
   int ir(0);
   TIterator* coefIter=_resList->MakeIterator();
   while(RooArgList *Ires = (RooArgList*)coefIter->Next()) {
	RooArgList ires = (*Ires);
	RooArgList icp = *(RooArgList*)(_cpList->At(ir));
	int type = (int)((RooAbsReal&)ires[ires.getSize()-1]).getVal();
	//     std::cout << "type " << type << std::endl;
	//     std::cout  << type << std::endl;
	ir++;
	//    if (type!=1&&type!=2&&type!=3&&type!=4) continue;
	_cpParams.add(icp[0]);
	_cpParams.add(icp[1]);  

	if(type==1) { //breit wigner
	   _resParams.add(ires[0]);
	   _resParams.add(ires[1]);
	   _resParams.add(ires[2]);
	   _resParams.add(ires[3]);
	   int Spin = (int)((RooAbsReal&)ires[ires.getSize()-2]).getVal();
	   if(Spin>0) {
		_resParams.add(ires[4]);
		_resParams.add(ires[5]);
		_resParams.add(ires[6]);
		_resParams.add(ires[7]);
		_cpParams.add(icp[2]);
		_cpParams.add(icp[3]);
		_cpParams.add(icp[4]);
		_cpParams.add(icp[5]);
	   }
	} else if(type==2) { //f0 flatte
	   _resParams.add(ires[0]);
	   _resParams.add(ires[1]);
	   _resParams.add(ires[2]);
	   _resParams.add(ires[3]);      
	   _resParams.add(ires[4]);        
	} else if(type==3||type==4||type==5) { //noresonace
	   _resParams.add(ires[0]);
	   _resParams.add(ires[1]);
	} else if(type==10) { //Spline
	   for(int i=0; i<ires.getSize()-1; ++i) _resParams.add(ires[i]);
	   MakeSpline(ires);
	}
   }
   delete coefIter;

   switch(dtype)
   {
	case SingleSided:
	   _basisCosh = declareBasis("exp(-@0/@1)*cosh(@0*@2/2)", RooArgList(tau,dgamma));
	   _basisSinh = declareBasis("exp(-@0/@1)*sinh(@0*@2/2)", RooArgList(tau,dgamma));
	   _basisCos = declareBasis("exp(-@0/@1)*cos(@0*@2)",RooArgList(tau, dm));
	   _basisSin = declareBasis("exp(-@0/@1)*sin(@0*@2)",RooArgList(tau, dm));
	   break;
	case Flipped:
	   _basisCosh = declareBasis("exp(@0/@1)*cosh(@0*@2/2)", RooArgList(tau,dgamma));
	   _basisSinh = declareBasis("exp(@0/@1)*sinh(@0*@2/2)", RooArgList(tau,dgamma));
	   _basisCos = declareBasis("exp(@0/@1)*cos(@0*@2)",RooArgList(tau, dm));
	   _basisSin = declareBasis("exp(@0/@1)*sin(@0*@2)",RooArgList(tau, dm));
	   break;
	case DoubleSided:
	   _basisCosh = declareBasis("exp(-abs(@0)/@1)*cosh(@0*@2/2)", RooArgList(tau,dgamma));
	   _basisSinh = declareBasis("exp(-abs(@0)/@1)*sinh(@0*@2/2)", RooArgList(tau,dgamma));
	   _basisCos = declareBasis("exp(-abs(@0)/@1)*cos(@0*@2)",RooArgList(tau, dm));
	   _basisSin = declareBasis("exp(-abs(@0)/@1)*sin(@0*@2)",RooArgList(tau, dm));
	   break;
   }
   _pdfmax = new Double_t; *_pdfmax = -1;
   CalCoupling();
   std::cout << " Calculate DPTermsIntegral " << std::endl;
   DPTermsIntegralMethod1();
   //  cout << "DPTermsIntegral " << _RsumInt << " " <<  _RdifInt << " " <<  _RInterfInt.Re() << " " << _RInterfInt.Im() << endl;
}


