void RooDalitzTimeCPCBTAG::CombineTag() const
{
   if( _tag1==0 && _tag2==0 ){
	_tag = 0;
	_avgMistag = 0.5;
	_delMistag = 0.0;
   } 
   if( _tag1!=0 && _tag2 == 0 ){
	_tag = _tag1;
	_avgMistag = MisTag(1);
	_delMistag = delMisTag(1);
   }
   if( _tag1==0 && _tag2 != 0 ){
	_tag = _tag2;
	_avgMistag = MisTag(2);
	_delMistag = delMisTag(2);
   }
   if( _tag1*_tag2 != 0 ){
	double mistag1 = MisTag(1);
	double mistag2 = MisTag(2);
	double dw1 = delMisTag(1);
	double dw2 = delMisTag(2);
	double wp1 = mistag1 +dw1/2.;
	double wp2 = mistag2 +dw2/2.;
	double wm1 = mistag1 -dw1/2.;
	double wm2 = mistag2 -dw2/2.;
	
	double cbwp,cbwm;

	if( _tag1 == _tag2 ){
	   _tag = _tag1;
	   cbwp = wp1*wp2/(wp1*wp2+(1.-wp1)*(1.-wp2));
	   cbwm = wm1*wm2/(wm1*wm2+(1.-wm1)*(1.-wm2));      

	}else{
	   if( mistag1 < mistag2 ){
		_tag = _tag1;
		cbwp = wp1*(1.-wp2)/(wp1*(1.-wp2)+(1.-wp1)*wp2);
		cbwm = wm1*(1.-wm2)/(wm1*(1.-wm2)+(1.-wm1)*wm2);
	   }else{
		_tag = _tag2;
		cbwp = wp2*(1.-wp1)/(wp1*(1.-wp2)+(1.-wp1)*wp2);
		cbwm = wm2*(1.-wm1)/(wm1*(1.-wm2)+(1.-wm1)*wm2);
	   }

	}
	_avgMistag = (cbwp+cbwm)/2.;
	_delMistag = cbwp-cbwm;      
   }

}


Double_t RooDalitzTimeCPCBTAG::MisTag(int itag) const
{
   double mistag(0.5);
   if(itag == 1) mistag = _eta1;
   else if(itag == 2) mistag = _eta2;
   else {return mistag;}
   if( (itag==1&&_tag1==0)||(itag==2&&_tag2==0) ) return mistag;

   //do calibration
   double p0, p1, etac;
   p0   = ( (RooAbsReal&)_Calibtag[(itag-1)*3]   ).getVal();
   p1   = ( (RooAbsReal&)_Calibtag[(itag-1)*3+1] ).getVal();
   etac = ( (RooAbsReal&)_Calibtag[(itag-1)*3+2] ).getVal();

   double mistag_c = p0+p1*(mistag-etac);
   //if(mistag_c>0.5) mistag_c = 0.5; // keep it ?

   return mistag_c;
}


Double_t RooDalitzTimeCPCBTAG::delMisTag(int itag) const
{
   double mistag(0.5);
   if(itag == 1) mistag = _eta1;
   else if(itag == 2) mistag = _eta2;

   //if(mistag<0.001 || mistag>=0.5) return 0.0;
   if( (itag==1&&_tag1==0)||(itag==2&&_tag2==0) ) return 0.0;

   //do calibration
   double dp0, dp1, etac;
   dp0  = ( (RooAbsReal&)_dCalibtag[(itag-1)*2]   ).getVal();
   dp1  = ( (RooAbsReal&)_dCalibtag[(itag-1)*2+1] ).getVal();
   etac = ( (RooAbsReal&)_Calibtag[(itag-1)*3+2]  ).getVal();

   double mistag_c =  dp0+dp1*(mistag-etac);
   return mistag_c;
}

Double_t RooDalitzTimeCPCBTAG::tageff() const
{
   double teff(0);
   int ios = (int)(_eta1/0.05)+1;
   int iss = (int)(_eta2/0.05)+1; 

   if(_tag1!=0&&_tag2!=0) { //Both
	teff = ((RooAbsReal&)_efftag[0]).getVal();
	//teff *= _etapdf.GetBinContent(ios,1)*_etapdf.GetBinContent(iss,2);
   } else if(_tag1!=0&&_tag2==0) { //OS only
	teff = ((RooAbsReal&)_efftag[1]).getVal();
	//teff *= _etapdf.GetBinContent(ios,1);
   } else if(_tag1==0&&_tag2!=0) { //SS only
	teff = ((RooAbsReal&)_efftag[2]).getVal();
	//teff *= _etapdf.GetBinContent(iss,2);
   } else {
	teff = 1.0-((RooAbsReal&)_efftag[0]).getVal()-((RooAbsReal&)_efftag[1]).getVal()-((RooAbsReal&)_efftag[2]).getVal();
   }

   if(teff<1e-10) std::cout << "tagging eff " << teff << std::endl;
   return teff;
}

//_____________________________________________________________________________
Double_t RooDalitzTimeCPCBTAG::coefficient(Int_t basisIndex) const
{
   // B0    : _tag = +1 
   // B0bar : _tag = -1 

   CombineTag();
   double as = (1.0+_tag*(1.-2.*(_avgMistag+_delMistag/2.)))+_RP*(1.0-_tag*(1.-2.*(_avgMistag-_delMistag/2.)));
   double ad = (1.0+_tag*(1.-2.*(_avgMistag+_delMistag/2.)))-_RP*(1.0-_tag*(1.-2.*(_avgMistag-_delMistag/2.)));

   if( basisIndex == _basisCosh )      return  tageff()*as*_Rsum/2.0;             
   else if( basisIndex == _basisSinh ) return -1.0*tageff()*as*_RInterf.Re()/2.0; 
   else if( basisIndex == _basisCos  ) return  tageff()*ad*_Rdif/2.0;             
   else if( basisIndex == _basisSin  ) return -1.0*tageff()*ad*_RInterf.Im()/2.0; 

   return 0 ;
}

