Int_t RooDalitzTimeCPCBTAG::getCoefAnalyticalIntegral(Int_t /*code*/, RooArgSet& allVars, RooArgSet& analVars, const char* rangeName) const 
{
   // Advertize existance of own integration over the Dalitz plot.

   //std::cout<<"++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++"<<std::endl;
   //std::cout<<"Requested integration over these variables: "<<std::endl;
   //allVars.Print("V");
   //std::cout<<"++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++"<<std::endl;

   RooArgSet List;
   List.add(*(_chi.absArg()));
   List.add(*(_cosH.absArg()));
   List.add(*(_coshh.absArg()));
   List.add(*(_mhh.absArg()));
   List.add(*(_tag1.absArg()));
   List.add(*(_eta1.absArg()));
   List.add(*(_tag2.absArg()));
   List.add(*(_eta2.absArg()));
   if( matchArgs(allVars, analVars, List) )  return 6;

   RooArgSet List1;
   List1.add(*(_chi.absArg()));
   List1.add(*(_cosH.absArg()));
   List1.add(*(_coshh.absArg()));
   List1.add(*(_mhh.absArg()));
   List1.add(*(_tag1.absArg()));
   List1.add(*(_tag2.absArg()));
   if( matchArgs(allVars, analVars, List1) )  return 5;
   if( matchArgs(allVars, analVars, _mhh, _coshh, _cosH, _chi) )  return 2;
   if( matchArgs(allVars, analVars, _tag1, _tag2) ) return 1;

   return 0 ;
}

Double_t RooDalitzTimeCPCBTAG::coefAnalyticalIntegral(Int_t basisIndex, Int_t code, const char* rangeName) const 
{
   double NormFactor(1);
   double as,ad;
   //  cout << "Integral code " << code << endl;
   switch(code) {

	case 0: // No integration
	   return coefficient(basisIndex);

	case 1: // Integration over 'tag'
	   if(basisIndex==_basisCosh)      { DPTerms(); return _Rsum*(1.0+_RP)/2.0; }
	   else if(basisIndex==_basisSinh) { DPTerms(); return -_RInterf.Re()*(1.0+_RP)/2.0;}
	   else if(basisIndex==_basisCos) return (1.0-_RP)*_Rdif/2.0;   
	   else if(basisIndex==_basisSin) return -(1.0-_RP)*_RInterf.Im()/2.0;
	   else assert(0);

	case 2: // Integration over mass, coshel
	   CombineTag();
	   as = (1.0+_tag*(1.-2.*(_avgMistag+_delMistag/2.)))+_RP*(1.0-_tag*(1.-2.*(_avgMistag-_delMistag/2.)));
	   ad = (1.0+_tag*(1.-2.*(_avgMistag+_delMistag/2.)))-_RP*(1.0-_tag*(1.-2.*(_avgMistag-_delMistag/2.)));

	   if(basisIndex == _basisCosh)        return  tageff()*as*_RsumInt/2.0;        // tageff()*(1.-_tag*_delMistag)*_Rsum;
	   else if(basisIndex == _basisSinh)   return -tageff()*as*_RInterfInt.Re()/2.0;//-tageff()*(1.-_tag*_delMistag)*_RInterf.Re();
	   else if(basisIndex == _basisCos)    return  tageff()*ad*_RdifInt/2.0;        //(1.0-2.*_avgMistag)*tageff()*_tag*_Rdif;
	   else if(basisIndex == _basisSin)    return -1.0*tageff()*ad*_RInterfInt.Im()/2.0;    
	   else assert(0);

	case 5: // Integration over 'tag', mass, coshel
	   if( basisIndex==_basisCosh ){
		DPTermsIntegral(); 
		_redoInt = false; 
		//      std::cout <<  std::endl;
		//      std::cout << " calculate DP Integral " << _RsumInt ;
		return _RsumInt*(1.0+_RP)/2.0;
	   }else if( basisIndex==_basisSinh ){
		if(_redoInt) DPTermsIntegral(); 
		return -_RInterfInt.Re()*(1.0+_RP)/2.0;

	   }else if( basisIndex==_basisCos ){
		return (1.0-_RP)*_RdifInt/2.0;

	   }else if( basisIndex==_basisSin ){
		_redoInt = true; 
		return -(1.0-_RP)*_RInterfInt.Im()/2.0;

	   }else{ assert(0); }

	case 6: // Integration over 'tag', mass, coshel, mistag
	   NormFactor = (_eta1.max(rangeName)-_eta1.min(rangeName))*(_eta2.max(rangeName)-_eta2.min(rangeName));
	   if( basisIndex==_basisCosh ){
		DPTermsIntegral(); 
		_redoInt = false; 
		return NormFactor*_RsumInt*(1.0+_RP)/2.0;

	   }else if( basisIndex==_basisSinh ){
		if(_redoInt) DPTermsIntegral(); 
		return -NormFactor*_RInterfInt.Re()*(1.0+_RP)/2.0;

	   }else if( basisIndex==_basisCos ){
		return NormFactor*(1.0-_RP)*_RdifInt/2.0;

	   }else if( basisIndex==_basisSin ){
		_redoInt = true; 
		return -NormFactor*(1.0-_RP)*_RInterfInt.Im()/2.0;

	   }else{ assert(0); }

	default: assert(0);

   }

   return 0;
}


