void RooDalitzTimeCPCBTAG::DPTerms() const//Double_t &Rsum, Double_t &Rdif, TComplex &RInterf) {
{
   // Evaluate |A|^2 +/- |Abar|^2 term in the B0-B0bar time-evolution equation. 
   _Rsum = 0;
   _Rdif = 0;
   _RInterf = TComplex(0);

   //double Rsum(0), Rdif(0);
   //TComplex RInterf(0);
   if(!kine_limits(_mhh))   return;
   if(fabs(_cosH)>1||fabs(_coshh)>1) return;  
   double m2pp = _mhh*_mhh;
   double xeff = efficiency(_mhh,_coshh,_cosH,_chi);//efficiency(_mhh,_coshh)*effcosH(m2pp, _cosH)*effchi(m2pp,_chi);
   double pB = getpB(_mhh);
   double pR = getpR(_mhh);
   double effphsp = pR*pB*xeff;

   Jpsihh_dlz *xdlz = new Jpsihh_dlz();
   //cout << "_Rsum _Rdif _RInterf " << _Rsum << " " << _Rdif << " " << _RInterf << endl;
   filldlz(*xdlz, _mhh, _coshh);
   TComplex H0(0), Hp(0), Hm(0);
   TComplex H0bar(0), Hpbar(0), Hmbar(0);
   amplitude(0,*xdlz, H0, H0bar);
   amplitude(1,*xdlz, Hp, Hpbar);
   amplitude(-1,*xdlz, Hm, Hmbar);
   double R = Rate(H0, Hp, Hm, _cosH, _chi);
   double Rbar = Rate(H0bar, Hpbar, Hmbar, _cosH, _chi);

   _Rsum = 0.5*(R+Rbar)* effphsp;
   _Rdif = 0.5*(R-Rbar)* effphsp;
   _RInterf = InterfRate(H0, Hp, Hm, H0bar, Hpbar, Hmbar, _cosH, _chi) * effphsp ; 
   //cout << "_Rsum _Rdif _RInterf " << _Rsum << " " << _Rdif << " " << _RInterf << endl;
   delete xdlz;
}

void RooDalitzTimeCPCBTAG::PrintDPInt()
{
   DPTermsIntegral();
   std::cout << "DPTermsIntegral " << _RsumInt << " " <<  _RdifInt << " " <<  _RInterfInt.Re() << " " << _RInterfInt.Im() << std::endl;
}

//Integration of m(hh) and coshh; already integral over chi and cosH in RateIntegral
void RooDalitzTimeCPCBTAG::DPTermsIntegralMethod1() const
{

   int nr = _resList->GetSize();
   for(int ir1=0; ir1<nr; ++ir1) {
	for(int ir2=0; ir2<nr; ++ir2) {
	   for(int ih=0; ih<4; ++ih) {//helicity
		HH[ih][ir1][ir2] = 0.0;
	   }
	}
   }
   double hx = (dlz_hx-dlz_lx)/2./np_dlzx;
   double hy = (dlz_hy-dlz_ly)/2./np_dlzy;
   // double hy1 = (dlz_hy-dlz_y_cut)/2./(np_dlzy*0.8);
   //double hr = hy1/hy;

   int ng = pdlz->size();
   double RsumInt = 0;
   double RdifInt = 0;
   double R,Rbar;
   TComplex RInterfInt = TComplex(0);
   TComplex AAbarstar;
   for(int ig = 0; ig<ng; ++ig) {
	Jpsihh_dlz &p = *(*pdlz)[ig];
	//Jpsihh_dlz p = pdlz[ig];
	TComplex H0(0), Hp(0), Hm(0);
	TComplex H0bar(0), Hpbar(0), Hmbar(0);
	amplitude(0,p, H0, H0bar);
	amplitude(1,p, Hp, Hpbar);
	amplitude(-1,p, Hm, Hmbar);
	//    if(ig==0) printf("\n check cached pdlz %10.6f %10.6f",  p.dre[0][1], p.dre[1][1]);
	R = RateIntegral(H0, Hp, Hm, p);
	Rbar = RateIntegral(H0bar, Hpbar, Hmbar, p);
	AAbarstar = InterfRateIntegral(H0,Hp,Hm,H0bar,Hpbar, Hmbar, p);
	/*
	   double pB = getpB(p.mpp);
	   double pR = getpR(p.mpp);

	   double xeff = 1.0;
	   double effphsp = pR*pB*xeff;
	   */
	double effphsp = p.phsp;
	RsumInt += 0.5*(R+Rbar)*effphsp;
	RdifInt += 0.5*(R-Rbar)*effphsp;
	RInterfInt += AAbarstar*effphsp;
	for(int ir1=0; ir1<nr; ++ir1) {
	   for(int ir2=0; ir2<nr; ++ir2) {
		for(int ih=0; ih<=2; ++ih) {
		   int iI = 1;
		   if(ih==1) iI = 0;
		   HH[ih][ir1][ir2] += effphsp*TComplex(p.dre[ir1][ih],p.dim[ir1][ih]) *
			TComplex::Conjugate(TComplex(p.dre[ir2][ih],p.dim[ir2][ih])) * p.Inte[iI];
		}
	   }  
	}
	for(int ir1=0; ir1<nr; ++ir1) {
	   for(int ir2=0; ir2<nr; ++ir2) {
		int iI = 2;
		HH[3][ir1][ir2] += effphsp*TComplex(p.dre[ir1][2],p.dim[ir1][2]) *
		   TComplex::Conjugate(TComplex(p.dre[ir2][0],p.dim[ir2][0])) * p.Inte[iI];
	   }
	}  
   }
   _RsumInt = RsumInt * hx*hy;
   _RdifInt = RdifInt * hx*hy;
   _RInterfInt = RInterfInt *hx*hy;
   //cout<<" ----------------------------"<<endl;
   //cout<<"  Check of integral. "<<endl;
   //cout<<" ----------------------------"<<endl;

}


//Integration of m(hh) and coshh; already integral over chi and cosH in RateIntegral
void RooDalitzTimeCPCBTAG::DPTermsIntegral() const
{
   CalCoupling();
   if(checkchange()) {
	DPTermsIntegralMethod1();
   } else {
	int nr = _resList->GetSize();
	double hx = (dlz_hx-dlz_lx)/2./np_dlzx;
	double hy = (dlz_hy-dlz_ly)/2./(np_dlzy);
	double RsumInt = 0;
	double RdifInt = 0;
	TComplex RInterfInt = TComplex(0);
	for(int ir1=0; ir1<nr; ++ir1) {
	   for(int ir2=0; ir2<nr; ++ir2) {
		for(int ih=0; ih<3; ++ih) {
		   RsumInt += (0.5*HH[ih][ir1][ir2]*
			   (HHR[ir1][ih]*TComplex::Conjugate(HHR[ir2][ih])
			    +HHRbar[ir1][ih]*TComplex::Conjugate(HHRbar[ir2][ih]))).Re();
		   RdifInt += (0.5*HH[ih][ir1][ir2]*
			   (HHR[ir1][ih]*TComplex::Conjugate(HHR[ir2][ih])
			    -HHRbar[ir1][ih]*TComplex::Conjugate(HHRbar[ir2][ih]))).Re();   
		   RInterfInt +=  HH[ih][ir1][ir2] * HHRbar[ir1][ih]*TComplex::Conjugate(HHR[ir2][ih]);   
		}
		RsumInt += (0.5*HH[3][ir1][ir2]*
			(HHR[ir1][2]*TComplex::Conjugate(HHR[ir2][0])
			 +HHRbar[ir1][2]*TComplex::Conjugate(HHRbar[ir2][0]))).Re();  
		RdifInt += (0.5*HH[3][ir1][ir2]*
			(HHR[ir1][2]*TComplex::Conjugate(HHR[ir2][0])
			 -HHRbar[ir1][2]*TComplex::Conjugate(HHRbar[ir2][0]))).Re();  
		RInterfInt +=  0.5*HH[3][ir1][ir2] *HHRbar[ir1][2]*TComplex::Conjugate(HHR[ir2][0])
		   +0.5*TComplex::Conjugate(HH[3][ir1][ir2]*HHR[ir1][2]*TComplex::Conjugate(HHRbar[ir2][0]));
		//HH[3][ir1][ir2])*HHRbar[ir1][0]*TComplex::Conjugate(HHRbar[ir2][2]));
	   }
	}
	_RsumInt = RsumInt * hx*hy;
	_RdifInt = RdifInt * hx*hy;
	_RInterfInt = RInterfInt *hx*hy;
   }
   //if constraint f2' do this calculation: f2' is the second resonance.

#ifdef F2CON
   double v0int[21], vlint[21], veint[21];
   getInt(v0int, vlint, veint);
   FFF2 = (v0int[1]+vlint[1]+veint[1]);
   //  std::cout << "FFF2" << FFF2 << std::endl;
#endif

   //update cached resparam
   int ir(0);
   TIterator* coefIter=_resList->MakeIterator();
   while(RooArgList* Ires = (RooArgList*)coefIter->Next()) {
	RooArgList ires = (*Ires);
	int type = (int)((RooAbsReal&)ires[ires.getSize()-1]).getVal();
	double m0 = 0;
	double g0 = 0;
	double rg = 0;

	if(type==1) { //breit wigner
	   m0 = ((RooAbsReal&)ires[ires.getSize()-4]).getVal();
	   g0 = ((RooAbsReal&)ires[ires.getSize()-3]).getVal();
	} else if(type==2) { //f0 flatte
	   m0 = ((RooAbsReal&)ires[2]).getVal();
	   g0 = ((RooAbsReal&)ires[3]).getVal();
	   rg = ((RooAbsReal&)ires[4]).getVal();
	} else if(type==10) {
	   for(int it3=0; it3<ires.getSize(); ++it3) {
		_resSpnCache[it3] = ((RooAbsReal&)ires[it3]).getVal();
		//          std::cout << _resSpnCache[it3] << std::endl;
	   }
	}
	_resParCache[3*ir+0] = m0;
	_resParCache[3*ir+1] = g0;
	_resParCache[3*ir+2] = rg;
	ir++;
   }
   delete coefIter;

}



void RooDalitzTimeCPCBTAG::getInt(double *v0int, double *vlint, double *veint, Bool_t force, double ylo, double yhi) const
{
   int nres = _resList->GetSize();
   double a0[21],al[21],ae[21];
   double A0[21],Al[21],Ae[21];
   for(int i=0; i<21; ++i) {
	a0[i] = 0;
	al[i] = 0;
	ae[i] = 0;
	A0[i] = 0;
	Al[i] = 0;
	Ae[i] = 0;
   }

   double hx = (dlz_hx-dlz_lx)/2./np_dlzx;
   double hy = (dlz_hy-dlz_ly)/2./(np_dlzy);

   int ng = pdlz->size();

   for(int ig = 0; ig<ng; ++ig) {
	Jpsihh_dlz &p = *(*pdlz)[ig];
	if(!(p.mpp>ylo&&p.mpp<yhi)) continue;
	Amplitude(0,p, &a0[0], force);
	Amplitude(1,p, &al[0], force);
	Amplitude(-1,p, &ae[0], force);

	double pB = getpB(p.mpp);
	double pR = getpR(p.mpp);

	double xeff = 1.0;

	//    xeff = efficiency(p.mpp,p.cospp);
	/*  double m2pp = p.mpp*p.mpp;
	    Double_t I1 = effcosHIntegral(m2pp, 1);
	    Double_t I2 = effcosHIntegral(m2pp, 2);
	    */
	double effphsp = pR*pB*xeff;

	for(int i=0; i<=nres; ++i) {
	   A0[i] += a0[i]*effphsp;//*I1;
	   Al[i] += al[i]*effphsp;//*I2;
	   Ae[i] += ae[i]*effphsp;//*I2;
	}
   }

   double sum = A0[0]+Al[0]+Ae[0];  
   //  std::cout<<< "sum int " << sum << std::endl;
   for(int k=1; k<=nres;++k) {
	v0int[k-1] = A0[k]/sum;
	vlint[k-1] = Al[k]/sum;
	veint[k-1] = Ae[k]/sum;
   }

}

Double_t RooDalitzTimeCPCBTAG::ModT(Double_t xt, Double_t xmhh,
	Double_t xcoshh,
	Double_t xcosH, Double_t xchi)
{
   _t = xt;
   _mhh = xmhh;
   _coshh = xcoshh;
   _cosH = xcosH;
   _chi = xchi;

   DPTerms();
   double C = _Rdif;
   double S = _RInterf.Im();
   //ASY = S*sin(dt)-C*cos(dt)
   double norm = sqrt(C*C+S*S);
   if(norm<1e-10) return xt;
   C = C/norm; S = S/norm;
   double delta = TMath::ATan2(C,S);
   double tm = _dm * _t - delta;
   tm = fmod(tm, 2.*TMath::Pi());
   if(tm<0) tm += 2.*TMath::Pi();
   return tm/_dm;
}

Int_t RooDalitzTimeCPCBTAG::GetTagDec(Int_t tag1, Double_t wtag1,
	Int_t tag2, Double_t wtag2,
	Double_t &wtag)
{
   wtag = 0.5;
   if(tag1==0&&tag2==0) return 0;
   _tag1 = tag1;
   _tag2 = tag2;

   _eta1 = wtag1;
   _eta2 = wtag2;
   CombineTag();
   if((1.-2.*_avgMistag)>1e-10) {wtag = _avgMistag; return _tag;}
   else if(fabs(1.-2.*_avgMistag)<1e-10) {wtag = 0.5; return 0;}
   else {wtag = 1.-_avgMistag; return -1*_tag;}

}

