void RooDalitzTimeCPCBTAG::initGenerator(Int_t code) {
   // assert(code==2);
   if (*_pdfmax>0) return;
   // sample Dalitz space to find the highest pdf  
   *_pdfmax=-1;
   int nsample=0;
   while (nsample++<20000) {
	Double_t pdftmp = sampleEvent();
	if (pdftmp>*_pdfmax) *_pdfmax=pdftmp;
   }
	*_pdfmax*=1.15; // increase 5% for safety
	//  cout << " pdfmax = " << (*_pdfmax) << endl;
}


Double_t RooDalitzTimeCPCBTAG::sampleEvent() {
   // Sample a uniform distribution with exponential. return a possible max pdf/exp(gammamin)
   double vrnd[3];
   RooRandom::uniform(3, vrnd);
   _coshh = (_coshh.max()-_coshh.min())*vrnd[0]+_coshh.min();
   _chi = (_chi.max()-_chi.min())*vrnd[1]+_chi.min();
   _cosH = (_cosH.max()-_cosH.min())*vrnd[2]+_cosH.min();
   while(1) {
	double vrnd3 = RooRandom::uniform();
	_mhh = (_MR-_ML)*vrnd3+_ML;//(_mhh.max()-_mhh.min())*vrnd3+_mhh.min();
	if(kine_limits(_mhh)) {
	   if(_mhh<1.05) {
		break; 
	   } else {
		if(RooRandom::uniform()<0.025) {  //for >1.05 factor 0.025 scale : two ladder MC
		   break;
		}
	   }
	}
   }
   DPTerms();
   //(_f0*cosh(dgt)+_f1*sinh(dgt)+_f2*cos(dmt)+_f3*sin(dmt));
   double f0 = _Rsum ; 
   double f1 = -1.0*_RInterf.Re();
   double f2 = _Rdif; 
   double f3 =  -1.0*_RInterf.Im();
   //return maximum
   double max= TMath::Abs(f0)+TMath::Abs(f1)+sqrt(f2*f2+f3*f3);
   if(_mhh<1.05) max *= 0.025;
   return max;
}


void RooDalitzTimeCPCBTAG::generateEvent(Int_t code) 
{
   // Generate event. 
   //! Alert don't generate avgMistag. use avgMistag as pre-input
   //  cout << "generation code " << code << endl;
   //  assert(code==2);
   //  sampleEvent();
   //  cout << "generation " << _t << " " << _mhh << " " << _coshh << " " << _cosH << " " << _chi << endl;
   //  return;

   //cout<<" code type : "<< code<<endl;
   if(code==52) {
	double w1, w2;
	double rnd = RooRandom::uniform();
	double effbo = ((RooAbsReal&)_efftag[0]).getVal();
	double effos = ((RooAbsReal&)_efftag[1]).getVal();
	double effss = ((RooAbsReal&)_efftag[2]).getVal();
	int tagcat = 0;
	if(rnd<effos) { tagcat = 1; } //OS
	else if(rnd<effos+effss) { tagcat = 2;} //SS
	else if(rnd<effos+effss+effbo) { tagcat = 3; } //BO
	w2 = 0.5;
	w1 = 0.5;
	if(tagcat==1||tagcat==3) w1 = ((TH1D*)_etapdf.ProjectionX("pos",1,1))->GetRandom();
	if(tagcat==2||tagcat==3) w2 = ((TH1D*)_etapdf.ProjectionX("pss",2,2))->GetRandom();
	//if(tagcat==2||tagcat==3) w2 = ((TH1D*)_etapdf.ProjectionX("pss",1,1))->GetRandom();
	if(w2>=0.5) w2=0.5;
	if(w1>=0.5) w1=0.5;
	_eta1 = w1;
	_eta2 = w2;    
   }
   
   Double_t gammamin = 1/_tau-TMath::Abs(_dgamma)/2;
   while(1) {
	Double_t t = _t;
	if(code!=4&&code!=41) {
	   t = -log(RooRandom::uniform())/gammamin;
	   if (_dtype == Flipped || (_dtype == DoubleSided && RooRandom::uniform() <0.5) ) t *= -1;
	   if ( t<_t.min() || t>_t.max() ) continue;
	}

	if(code==51||code==52) {
	   _tag1 = 0;
	   _tag2 = 0;
	   if(_eta1-0.5<-1e-10) { 
		if(RooRandom::uniform()<0.5) {
		   _tag1 = 1;
		} else {
		   _tag1 = -1;
		}
	   }
	   if(_eta2-0.5<-1e-10) { 
		if(RooRandom::uniform()<0.5) {
		   _tag2 = 1;
		} else {
		   _tag2 = -1;
		}
	   }
	   if( (_tag1 == 0 && _eta1<0.5)||(_tag2 == 0 && _eta2<0.5) ){ cout<<" wrong tagged : "<<_tag1<<" "<<_tag2<<" "<<_eta1<<" "<<_eta2<<endl; }
	}
	Double_t dgt = _dgamma*t/2;
	Double_t dmt = _dm*t;
	Double_t ft = fabs(t);
	
	//not work for code=1;
	if(code!=1) sampleEvent();

	double f0 = coefficient(_basisCosh); 
	double f1 = coefficient(_basisSinh);
	double f2 = coefficient(_basisCos);
	double f3 = coefficient(_basisSin);    
	Double_t f = exp(-ft/_tau)*(f0*cosh(dgt)+f1*sinh(dgt)+f2*cos(dmt)+f3*sin(dmt));
	if(f < 0) {
	   std::cout << "RooDalitzTimeCPCBTAG::generateEvent(" << GetName() << ") ERROR: PDF value less than zero" << std::endl;
	   ::abort();
	}
	if(_mhh<1.05) f *= 0.025;
	Double_t w = exp(-ft*gammamin)*(*_pdfmax)*tageff();
	//    if(_tag==0) cout << "check max" << f/w << endl;
	if(w < f) {
	   // cout << "RooDalitzTimeCPCBTAG::generateEvent(" << GetName() << ") ERROR: Envelope function less than p.d.f. " << endl;
	   // cout << f0 << endl;
	   // cout << f1 << endl;
	   // cout << f2 << endl;
	   // cout << f3 << endl;
	   ::abort();
	}
	if(w*RooRandom::uniform() > f) continue;
	_t = t;
	break;
   }

}


